-- fortune_site_seed_star_position_texts_v2_delete_insert.sql
-- star_position_texts 専門用語非表示版
-- 目的: 結果ページにそのまま表示できる自然文へ差し替えます。
-- 方式: 既存の star_position_texts を削除してから、version=2 の50件を再投入します。
-- 前提: fortune_site_schema.sql および sanmei_stars / sanmei_positions の初期データ投入済み
-- 注意: 本番運用後に diagnosis_results.result_json と過去表示を保持している場合は、実行前にバックアップしてください。

begin;

-- 既存データを削除してから再投入します。
-- star_position_texts は診断結果生成用の文章マスタであり、過去の診断結果は diagnosis_results.result_json にスナップショット保存する想定です。
delete from public.star_position_texts;

insert into public.star_position_texts (
  star_id,
  position_id,
  title,
  free_text,
  premium_text,
  advice_text,
  version,
  is_active
)
select
  st.id,
  ps.id,
  v.title,
  v.free_text,
  v.premium_text,
  v.advice_text,
  2,
  true
from (values
  ('kansaku', 'head', '自分の軸で判断する人', 'あなたは物事を判断するとき、周囲の空気に流されるよりも、自分の中で納得できるかを大切にします。誰かの意見をそのまま受け入れるのではなく、一度自分の基準に照らして考えるタイプです。時間はかかっても、自分なりの答えを持てると迷いが少なくなります。', '価値観の面では、安易に人へ合わせるより「自分はどう考えるか」を確認することで安定します。強い意見を持つ人の前でも、内側では冷静に判断していることが多いでしょう。ただし、正しさを守ろうとしすぎると柔軟な選択肢を狭めることがあります。信頼できる人の視点を取り入れると、あなたの軸はさらに強くなります。', '迷ったときは、周囲の期待と自分の本音を分けて書き出すと判断しやすくなります。'),
  ('kansaku', 'chest', '静かに信頼を積み上げる人', 'あなたの中心には、決めたことを守り、時間をかけて積み上げる力があります。派手に目立つよりも、簡単にはぶれない姿勢で信頼を得ていくタイプです。自分のペースを乱されすぎると力が出にくくなりますが、守りたいものが明確になるほど粘り強く進めます。', '本質的には、自立心と継続力が大きな支えになります。人に合わせることもできますが、心の奥では「自分で決めたい」という感覚が強くあります。無理に柔らかく見せようとするより、守るべき軸を持っていることを前向きに使うと魅力になります。頑固さは、方向づけを間違えなければ大きな強みに変わります。', '自分を変えようとしすぎるより、長く守りたいものを明確にすると力を発揮しやすくなります。'),
  ('kansaku', 'left_hand', '仕事では継続力が評価される', '仕事では、短期的な勢いよりも、責任を持って続ける力が評価につながります。決められたことを守るだけでなく、自分なりの基準で品質を保つことが得意です。長く任される役割や、信頼の積み重ねが成果になる仕事で力を発揮しやすいでしょう。', '働き方では、成果がすぐに見えなくても地道に積み上げられる環境と相性が良いです。一方で、方針が頻繁に変わったり、場当たり的な判断を求められすぎると消耗しやすくなります。あなたの強みは「続けること」そのものではなく、続けながら質を守れることです。改善や管理、専門性の蓄積が必要な場で評価されやすいでしょう。', '仕事では、担当範囲と守るべき基準が明確な環境を選ぶと成果が出やすくなります。'),
  ('kansaku', 'right_hand', '親しい人には誠実に向き合う', '恋愛や身近な関係では、軽い言葉よりも、継続的な態度で信頼を示すタイプです。一度大切だと思った相手には、時間をかけて誠実に向き合います。ただし、自分のペースを守りたい気持ちが強くなると、相手から距離を感じられることもあります。', '親しい関係では、安定感が大きな魅力になります。相手に振り回されすぎず、長く続く関係を育てる力があります。一方で、不満を溜めたまま黙ってしまうと、ある日突然距離を置くように見えることがあります。安心した関係ほど、早めに気持ちを言葉にすることが大切です。', '大切な人には、態度だけで伝えるのではなく、安心していることや困っていることを短く言葉にしてみてください。'),
  ('kansaku', 'stomach', '長く続けられる居場所を求める', '人生が進むほど、あなたは一時的な刺激よりも、長く続けられる居場所や役割を大切にしたくなります。誰かに急かされる生き方より、自分のペースで積み上げていくことに満足を感じやすいでしょう。焦らず育てたものが、後から大きな支えになります。', '長期的には、自分の基盤を持つことが大きなテーマになります。人の評価に振り回されるより、自分が守りたい生活、仕事、人間関係を少しずつ形にすることで安定します。若い時期には変化に合わせて動けても、年齢を重ねるほど「自分の場所」が必要になります。無理なく続けられる設計が幸福感につながります。', '将来を考えるときは、短期的な華やかさより、長く続けても心がすり減らない選択を重視してください。'),
  ('sekimon', 'head', '人との関係性から判断する人', 'あなたは物事を考えるとき、自分ひとりの正解だけでなく、周囲との関係性や場の流れも大切にします。誰がどう感じるか、全体がどう動くかを自然に見ています。対立を避けるだけでなく、人と人をつなぎながら現実的な答えを探すタイプです。', '価値観の面では、孤立して正しさを貫くより、関係性の中で答えを見つける傾向があります。意見の違いを調整したり、複数の立場をつなぐことに強みがあります。ただし、場を壊したくない気持ちが強すぎると、自分の希望を曖昧にしやすくなります。自分の意見を持ったうえで調和を選ぶと、判断の質が上がります。', '人の意見を聞く前に、自分はどうしたいのかを一度メモしておくと流されにくくなります。'),
  ('sekimon', 'chest', '人と人をつなぐ調整役', 'あなたの中心には、人との縁を広げ、場をなめらかにつなぐ力があります。ひとりで完結するより、誰かと関わることで自分らしさが出やすいタイプです。周囲の様子を見ながら自然に立ち位置を調整できるため、組織や仲間の中で力を発揮しやすいでしょう。', '本質的には、横のつながりを作ることが大きな才能になります。人の間に入り、空気を読み、自然に関係を整える力があります。一方で、誰にでも合わせられる分、自分の輪郭がぼやけやすいこともあります。周囲と協調しながらも、何を大切にしたいのかを持っておくと、あなたの調整力はより信頼されます。', '人をつなぐ力を使うほど魅力が出ますが、自分の希望を後回しにしすぎないことも大切です。'),
  ('sekimon', 'left_hand', '仕事では調整力が武器になる', '仕事では、人と人、部署と部署、考え方の違う相手をつなぐ場面で力を発揮します。ひとつの作業を黙々と進めるだけでなく、周囲を巻き込みながら物事を前に進めるタイプです。チームで成果を出す仕事や、関係者の多い仕事に適性があります。', '働き方では、連携や調整が必要な環境で評価されやすいでしょう。相手の立場を理解し、衝突を大きくせずに合意点を探せることが強みです。ただし、板挟みになる役割が続くと疲れやすいため、責任範囲を明確にしておくことが大切です。人を支えるだけでなく、あなた自身の成果も見える形にすると評価が安定します。', '仕事では、調整役に回るだけでなく、自分が出した価値を記録しておくと評価につながります。'),
  ('sekimon', 'right_hand', '親しい人とは一体感を求める', '恋愛や身近な関係では、ひとりで完結するより、相手と気持ちを共有することを大切にします。相手の様子をよく見て、自然に合わせることができます。ただし、合わせることが当たり前になると、自分だけが我慢している感覚が出やすくなります。', '親しい関係では、相手を受け入れる柔らかさが魅力になります。相手の気分や状況を読み取り、関係を壊さないように動ける人です。一方で、本音を飲み込みすぎると、後から不満が大きくなることがあります。長く続く関係には、優しさだけでなく、境界線も必要です。', '相手に合わせる前に、自分が心地よい距離感も伝えると関係が健やかに続きます。'),
  ('sekimon', 'stomach', '人との縁が人生の支えになる', '人生が進むほど、あなたは信頼できる仲間や居場所の大切さを実感していきます。ひとりで成果を抱えるより、誰かと分かち合える環境に満たされやすいタイプです。人との縁を丁寧に育てることが、長期的な安心感につながります。', '長期的には、どんな人とつながるかが人生の質を大きく左右します。幅広い関係を持てる一方で、すべての人に合わせ続ける必要はありません。年齢を重ねるほど、ただ人が多い場所より、価値観を共有できる関係が大切になります。自分らしくいられる共同体を選ぶことで力が戻ります。', '将来の満足度を高めるには、数よりも質を意識して、人間関係を選び育てていくことが大切です。'),
  ('houkaku', 'head', '自然で心地よいものを選ぶ人', 'あなたは物事を判断するとき、理屈だけでなく、自然で無理がないかを大切にします。堅苦しい正解よりも、続けていて心地よいこと、周囲が明るくなることに価値を感じやすいタイプです。楽しさや余白があるほど、発想も判断も柔らかくなります。', '価値観の面では、過度に緊張した場より、のびのびと表現できる環境で判断力が冴えます。人を楽しませることや、わかりやすく伝えることに自然な感覚があります。ただし、深刻な話題を避けすぎると、大切な問題が後回しになることもあります。軽やかさと誠実さを両立できると、あなたらしい判断になります。', '迷ったときは、正しいかだけでなく「続けたときに明るい気持ちでいられるか」も判断材料にしてください。'),
  ('houkaku', 'chest', '自然体で魅力が伝わる人', 'あなたの中心には、飾りすぎず、自然体で人を惹きつける力があります。無理に特別なことをしなくても、楽しそうにしている姿や、素直な表現が周囲に伝わりやすいタイプです。深刻になりすぎない軽やかさが、あなたの魅力になります。', '本質的には、自分が楽しむことと、人に伝えることが結びつきやすい人です。場の空気を和ませたり、難しいことを親しみやすく見せたりする力があります。一方で、自由に表現できない環境が続くと、内側の明るさがしぼみやすくなります。成果だけを追うより、楽しさを含めた形で力を出すことが大切です。', '自分らしさを出すには、完璧に見せるより、自然に楽しめることを少しずつ表に出してみてください。'),
  ('houkaku', 'left_hand', '仕事では伝える力が活きる', '仕事では、情報や考えをわかりやすく伝える場面で力を発揮します。人を緊張させず、場を明るくしながら物事を進めることができます。発信、接客、企画、教育、場づくりなど、相手に届く形に変える仕事と相性が良いでしょう。', '働き方では、楽しさや人に伝える要素があるほど力が出ます。専門的な内容でも、相手が受け取りやすい形にすることが得意です。ただし、単調で閉じた作業だけが続くと意欲が落ちやすいかもしれません。成果を出すためには、自由な表現と一定の責任のバランスが必要です。', '仕事では、ただ作業をこなすより、誰に何を届ける仕事なのかを意識すると力が入りやすくなります。'),
  ('houkaku', 'right_hand', '親しい人には明るさで関わる', '恋愛や身近な関係では、重くなりすぎず、自然な会話や一緒に楽しむ時間を大切にします。相手を笑顔にしたい気持ちがあり、場を和ませることができます。ただし、真剣な話を避け続けると、相手には本音が見えにくくなることがあります。', '親しい関係では、一緒に過ごす時間の楽しさが愛情表現になりやすいでしょう。気軽な会話や日常の共有を通して関係を深めるタイプです。一方で、悩みや不安を軽く見せすぎると、相手に伝わらないまま溜め込むことがあります。明るさの中に、必要な本音も少し混ぜることが大切です。', '大切な話ほど冗談だけで流さず、短くても本音を添えると関係が深まりやすくなります。'),
  ('houkaku', 'stomach', '人生後半ほど自然体が大切になる', '人生が進むほど、あなたは無理に背伸びするより、自然体でいられる生き方に惹かれていきます。楽しさ、余白、人に伝えることが日々の満足につながります。自分が明るくいられる環境を選ぶことが、長期的な元気の源になります。', '長期的には、肩書きや評価だけでなく、自分が自然に笑えるかどうかが大切になります。人に合わせて硬くなりすぎると、本来の魅力が出にくくなります。年齢を重ねるほど、好きなことを表現したり、誰かと楽しさを分かち合ったりする時間が必要になります。軽やかさを失わない設計が、あなたの人生を豊かにします。', '将来を考えるときは、生活の中に楽しみや表現の余白を残すことを意識してください。'),
  ('chousho', 'head', '細かな違和感を見逃さない人', 'あなたは物事を判断するとき、周囲が見落とす小さな違和感や空気の変化に気づきやすい人です。言葉にならない雰囲気や、表情の奥にある感情を敏感に受け取ります。人と同じ見方をするより、自分だけの感覚を通して世界を理解するタイプです。', '価値観の面では、合理性だけでは割り切れない繊細な感覚を大切にします。美しいか、嘘がないか、自分の心が反応するかが判断基準になりやすいでしょう。その感性は大きな才能ですが、受け取りすぎると疲れやすくもあります。すべてを抱え込まず、感じたことを言葉や形にすることで整理されます。', '違和感を無視せず、なぜそう感じたのかを短い言葉にして残すと判断の助けになります。'),
  ('chousho', 'chest', '繊細さを力に変える人', 'あなたの中心には、人と違う視点や繊細な感受性があります。周囲が気にしないことにも心が動き、深く感じ取るタイプです。その分、傷つきやすさもありますが、感じたことを言葉や表現に変えられると、大きな魅力になります。', '本質的には、独自の感性を持つ人です。普通であることに安心するより、自分だけが感じたものを大切にしたい気持ちがあります。周囲に理解されない経験があっても、その感受性はあなたの深さにつながっています。無理に鈍くなるのではなく、安心して表現できる場を持つことが重要です。', '感じすぎる自分を否定せず、言葉・音・文章・デザインなど、外に出せる形を持つと楽になります。'),
  ('chousho', 'left_hand', '仕事では独自の視点が評価される', '仕事では、細かな違和感に気づく力や、人と違う角度から考える力が活きます。決められた型をそのままなぞるより、改善点を見つけたり、表現を磨いたりする場面で力を発揮しやすいでしょう。企画、文章、デザイン、分析、品質を見る仕事とも相性があります。', '働き方では、感性や観察力を使える環境で評価されやすいです。まだ言葉になっていないニーズや、微妙なズレを見つける力があります。ただし、批判や評価が強すぎる場では心が疲れやすくなります。安心して集中できる時間と、感性を活かせる役割があると成果につながります。', '仕事では、自分の感じた違和感をただの不満で終わらせず、改善案として伝えると評価されやすくなります。'),
  ('chousho', 'right_hand', '親しい人には深く感じて関わる', '恋愛や身近な関係では、相手の言葉の裏にある気持ちまで感じ取りやすいタイプです。浅い関係よりも、心の奥まで理解し合える関係を求めます。ただし、相手の反応を深読みしすぎると、ひとりで不安を大きくしてしまうことがあります。', '親しい関係では、細やかな気づきや感受性が魅力になります。相手の変化に気づき、言葉にしにくい気持ちにも寄り添える人です。一方で、自分の寂しさや不満を言えずに抱え込むと、急に距離を置きたくなることがあります。感じたことを少しずつ共有することが、関係を深める鍵です。', '不安を感じたときは、決めつける前に「こう感じたけれど合っている？」と確認してみてください。'),
  ('chousho', 'stomach', '人生後半ほど自分だけの表現が必要になる', '人生が進むほど、あなたは人と同じ正解より、自分だけの感性を形にすることを求めるようになります。感じたことを押し殺す生き方より、静かでも自分の表現を持てる生き方に満たされやすいでしょう。繊細さを守れる環境が大切です。', '長期的には、心が反応するものを無視しないことがテーマになります。周囲に合わせ続けるだけでは、内側の感性が疲れてしまいます。年齢を重ねるほど、ひとりで整える時間、創作する時間、本音を出せる相手が必要になります。あなたにとって表現は趣味にとどまらず、心を保つための大切な手段です。', '将来の生活には、ひとりで感性を整える時間と、自分を表現できる場所を必ず残してください。'),
  ('rokuzon', 'head', '人に必要なものを考える人', 'あなたは物事を判断するとき、自分だけの損得ではなく、相手や場に何が必要かを考えやすい人です。人の役に立つこと、場を満たすこと、現実的に動かせることに価値を感じます。理想だけで終わらせず、形にする力を大切にするタイプです。', '価値観の面では、誰かに必要とされることが判断の大きな材料になります。人やお金、時間など、現実的な資源をどう活かすかに感覚があります。一方で、求められるままに応えすぎると、負担を抱え込みやすくなります。何を与えるかだけでなく、どこまで引き受けるかを決めることで、あなたの力は健やかに使えます。', '判断に迷ったときは、相手のためになるかだけでなく、自分の余力が残るかも確認してください。'),
  ('rokuzon', 'chest', '人や場を満たす力を持つ人', 'あなたの中心には、人を惹きつけ、場に必要なものを集める力があります。面倒見がよく、誰かのために動くことで自分らしさが出やすいタイプです。現実感覚もあり、気持ちだけでなく実際に役立つ形へ落とし込めることが強みです。', '本質的には、与える力と現実を動かす力が結びついています。人を喜ばせたり、場を整えたりすることに自然と意識が向きます。ただし、愛情や責任感から背負いすぎると、自分の疲れを後回しにしやすいでしょう。人に与える力を長く使うには、受け取ることも同じくらい大切です。', '誰かのために動く力が魅力ですが、自分の時間やお金や心の余白も守るようにしてください。'),
  ('rokuzon', 'left_hand', '仕事では人を動かす力が活きる', '仕事では、人を集める、場を整える、必要な資源を動かす場面で力を発揮します。相手のニーズを感じ取り、現実的な形にすることが得意です。営業、企画、マネジメント、サービス、事業づくりなど、人と現実が交わる仕事で評価されやすいでしょう。', '働き方では、誰かの役に立っている実感が成果につながります。人の気持ちと現実的な条件を両方見られるため、調整役や推進役としても力を出せます。ただし、頼まれごとが増えすぎると自分の本来業務が圧迫されることがあります。貢献範囲を決めることで、持ち前の引力がより成果に変わります。', '仕事では、頼まれたことを全部受けるのではなく、成果につながる貢献を選ぶ意識を持ってください。'),
  ('rokuzon', 'right_hand', '親しい人には惜しみなく与える', '恋愛や身近な関係では、相手を喜ばせたい、支えたいという気持ちが自然に出やすいタイプです。気づくと相手のために動いていることも多いでしょう。ただし、与えることが当たり前になると、感謝されないことに寂しさを感じやすくなります。', '親しい関係では、面倒見の良さとあたたかさが魅力になります。相手のために時間や労力を使える人です。一方で、愛情と世話が近くなりすぎると、相手を甘やかしたり、自分が疲れたりすることがあります。長く良い関係を続けるには、与えることと受け取ることのバランスが必要です。', '親しい相手には、してあげるだけでなく、自分がしてほしいことも素直に伝えてください。'),
  ('rokuzon', 'stomach', '人生後半ほど豊かさの循環を求める', '人生が進むほど、あなたは人とのあたたかい循環や、現実的な豊かさを大切にしたくなります。誰かに必要とされることは大きな喜びですが、自分も満たされる関係や環境であることが重要です。与えるだけでなく受け取る流れがあるほど満足度が高まります。', '長期的には、人・お金・時間・愛情の循環をどう整えるかがテーマになります。人を支える力があるからこそ、自分を支える仕組みも必要です。年齢を重ねるほど、ただ忙しく人に尽くすより、自分も豊かになれる関わり方を選ぶことが大切になります。貢献と安心が両立すると、人生の充実感が増します。', '将来設計では、誰かを支える役割だけでなく、自分が安心して受け取れる仕組みも作ってください。'),
  ('shiroku', 'head', '確実に積み上げて考える人', 'あなたは物事を判断するとき、勢いや直感だけでなく、現実的に続けられるかを大切にします。小さな積み重ねや、日々の安定に価値を感じやすいタイプです。大きく変えるより、無理なく続く形を作ることで安心して前に進めます。', '価値観の面では、信頼、準備、蓄積が大切な軸になります。急な変化より、段階を踏んで整えていく方が力を出しやすいでしょう。細かな点まで気づけるため、計画や管理に強みがあります。一方で、失敗を避けたい気持ちが強すぎると、新しい可能性を試す前に閉じてしまうことがあります。', '迷ったときは、完璧な準備を待つより、小さく試して積み上げる方法を選ぶと動きやすくなります。'),
  ('shiroku', 'chest', '信頼を静かに積み重ねる人', 'あなたの中心には、小さなことを丁寧に積み重ねる力があります。派手な一発勝負より、日々の配慮や継続によって信頼を育てるタイプです。安心できる関係や環境を作ることが得意で、長く続くものほどあなたの良さが表れます。', '本質的には、堅実さと管理力が大きな魅力になります。細かなことに気づき、必要な準備を重ねられる人です。一方で、先の不安を考えすぎると、動き出すまでに時間がかかることがあります。安定を守る力は重要ですが、少しずつ変化を取り入れることで、あなたの積み重ねはさらに価値を持ちます。', '自分らしさを出すには、地味に見える努力を軽く扱わず、信頼を作る才能として認めてください。'),
  ('shiroku', 'left_hand', '仕事では管理力と配慮が活きる', '仕事では、細かな管理、準備、段取り、長期的な信頼づくりで力を発揮します。急に目立つ役割より、仕組みを整えたり、確実に進めたりする場面で評価されやすいでしょう。事務、運用、企画管理、顧客対応、サポートなどと相性があります。', '働き方では、継続的な改善や安定運用が必要な環境で強みが出ます。周囲が見落とす細部に気づき、トラブルを未然に防ぐ力があります。ただし、責任感から細部まで抱え込みすぎると疲れやすくなります。任せる仕組みや優先順位を作ることで、管理力がより大きな成果につながります。', '仕事では、全部を自分で抱えるより、手順化・共有化して信頼を広げると評価が上がります。'),
  ('shiroku', 'right_hand', '親しい人には安心感を与える', '恋愛や身近な関係では、急な盛り上がりより、安定した関わりを大切にします。相手の生活や気持ちを細やかに気にかけ、安心できる関係を育てるタイプです。ただし、心配が強くなると、相手を管理しすぎるように見えることがあります。', '親しい関係では、誠実さと日常的な配慮が魅力になります。相手の小さな変化に気づき、長く支える力があります。一方で、期待した形で返ってこないと寂しさを感じやすいかもしれません。相手を思う気持ちは大切ですが、相手の自由も尊重できると関係が安定します。', '大切な人には、心配から動く前に、相手が本当に望んでいることを確認してみてください。'),
  ('shiroku', 'stomach', '人生後半ほど安心できる基盤を求める', '人生が進むほど、あなたは安心できる生活基盤や、長く続く信頼関係を大切にしたくなります。短期間の刺激より、日々の積み重ねから生まれる安定に満たされやすいタイプです。自分のペースで整えた環境が、心の支えになります。', '長期的には、暮らし、人間関係、仕事の基盤をどう整えるかがテーマになります。大きな夢も、日々の小さな積み重ねによって実現する方が向いています。年齢を重ねるほど、無理のある挑戦より、続けられる形を選ぶことが重要になります。安定を退屈と見なさず、自分を支える土台として育てることが大切です。', '将来の満足度を高めるには、生活・お金・人間関係を少しずつ整える習慣を持ってください。'),
  ('shaki', 'head', 'まず動いて確かめる人', 'あなたは物事を判断するとき、考え続けるよりも、実際に動いて確かめることを大切にします。机上の理屈だけでは納得しにくく、現場感や手応えを重視するタイプです。迷って止まるより、行動しながら答えを見つけることで力が出ます。', '価値観の面では、スピード、実行、勝負どころを見極める感覚が大切になります。理屈よりも「やってみればわかる」という判断が強みです。ただし、急いで結論を出しすぎると、長期的な影響を見落とすことがあります。行動力に、少しだけ確認の時間を加えると、判断の精度が上がります。', 'すぐ動ける強みを活かしつつ、大きな決断の前には一度だけ立ち止まって確認すると失敗が減ります。'),
  ('shaki', 'chest', '行動で道を切り開く人', 'あなたの中心には、考えすぎるより動きながら突破していく力があります。目標が明確になるほど集中力が高まり、困難な場面でも前に進めるタイプです。じっと待つより、現場で動くことで自分らしさが表れます。', '本質的には、行動力と勝負強さを持つ人です。課題があるほど燃えやすく、プレッシャーの中で力を出せる面があります。一方で、何もすることがない状態や、決断が先延ばしになる環境ではストレスを感じやすいでしょう。強さをただの勢いで終わらせず、目的に向けて使うことが大切です。', '動けることは大きな才能です。力を使う方向を決めると、無駄な消耗が減って成果に変わります。'),
  ('shaki', 'left_hand', '仕事では突破力が評価される', '仕事では、スピード感や行動力が求められる場面で力を発揮します。困難な状況でも止まらず、まず前に進めることができます。営業、現場対応、プロジェクト推進、改善活動、競争のある環境などで評価されやすいでしょう。', '働き方では、目標が明確で、行動が成果につながる環境と相性が良いです。停滞した状況を動かしたり、誰かが迷っている場面で先に踏み出したりできます。ただし、周囲の準備が追いつかないまま進めると摩擦が起きやすくなります。スピードに説明を添えることで、周囲を巻き込みやすくなります。', '仕事では、早く動くだけでなく、なぜ今動くのかを周囲に共有すると信頼されやすくなります。'),
  ('shaki', 'right_hand', '親しい人にはまっすぐ向き合う', '恋愛や身近な関係では、遠回しな駆け引きより、まっすぐな態度が出やすいタイプです。好き嫌いや不満も比較的はっきり表れます。誠実さは魅力ですが、勢いが強いと相手には急かされているように感じられることがあります。', '親しい関係では、行動で愛情を示すことが多いでしょう。困っている相手のためにすぐ動ける頼もしさがあります。一方で、相手のペースを待つことが苦手になると、善意が圧力に見える場合があります。相手が求めているのは解決か共感かを確認すると、関係が整いやすくなります。', '大切な人が悩んでいるときは、すぐ解決策を出す前に「聞いてほしい？一緒に考える？」と確認してみてください。'),
  ('shaki', 'stomach', '人生後半ほど挑戦が必要になる', '人生が進むほど、あなたはただ安定するだけでは物足りなくなりやすいタイプです。何かに挑戦し、力を試し、前に進んでいる感覚が心の充実につながります。無理な競争ではなく、自分なりの目標を持つことで元気が戻ります。', '長期的には、挑戦し続けられるテーマを持つことが大切になります。安全な場所にいるだけでは、本来の行動力が眠ってしまうかもしれません。年齢を重ねても、体験や挑戦を通して自分を更新することが満足感につながります。ただし、常に戦い続ける必要はありません。休む時間を含めて、持続可能な挑戦を選ぶことが大切です。', '将来の設計には、安心だけでなく、自分の力を試せる目標をひとつ入れておくと充実しやすくなります。'),
  ('kengyu', 'head', 'きちんとした基準で判断する人', 'あなたは物事を判断するとき、その場の感情だけでなく、責任を果たせるか、周囲から見て信頼されるかを大切にします。曖昧な状態より、筋道や基準が整っている方が安心します。自分にも人にも、一定の誠実さを求めるタイプです。', '価値観の面では、役割、信頼、品位が大切な軸になります。どう見られるかを気にするだけでなく、期待に応えたい気持ちが強いでしょう。その姿勢は大きな強みですが、失敗を過度に恐れると身動きが取りにくくなります。完璧であることより、誠実に整え続けることを意識すると楽になります。', '判断に迷ったときは、完璧な正解より「誠実に説明できる選択か」を基準にすると動きやすくなります。'),
  ('kengyu', 'chest', '責任を美しく果たす人', 'あなたの中心には、与えられた役割をきちんと果たしたい気持ちがあります。雑に扱われることや、曖昧な責任には違和感を持ちやすいタイプです。品のある努力や、信頼に応える姿勢が、あなたの魅力として周囲に伝わります。', '本質的には、責任感と美意識を持つ人です。求められた水準に応えようとする力があり、きちんとした場で実力を発揮しやすいでしょう。一方で、評価や期待を背負いすぎると、自分に厳しくなりすぎることがあります。役割を果たすことと、自分を追い詰めることは分けて考える必要があります。', '自分らしさを発揮するには、責任を引き受けるだけでなく、無理な期待には線を引くことも大切です。'),
  ('kengyu', 'left_hand', '仕事では信頼される役割で輝く', '仕事では、責任ある役割や、品質・信用が求められる場面で力を発揮します。きちんと整える力があり、周囲から安心して任されやすいタイプです。管理、企画、専門職、対外対応、ブランドや品質に関わる仕事と相性があります。', '働き方では、評価基準が明確で、責任の所在がはっきりした環境で力を出しやすいでしょう。期待に応えるために努力できる一方、曖昧な指示や不公平な評価にはストレスを感じやすいです。自分の役割と裁量が合っていると、品のある成果を出せます。無理に裏方に徹するより、信頼される立場を引き受けることで伸びます。', '仕事では、責任範囲と評価基準を早めに確認すると、安心して実力を出しやすくなります。'),
  ('kengyu', 'right_hand', '親しい人にも誠実さを求める', '恋愛や身近な関係では、軽いノリだけではなく、誠実さや礼儀を大切にします。相手に対してきちんと向き合いたい気持ちがあり、雑に扱われると傷つきやすいでしょう。信頼できる関係では、深く責任を持って関わります。', '親しい関係では、約束を守ることや、相手を大切に扱うことが愛情表現になりやすいです。相手にも同じような誠実さを求めるため、いい加減な態度には敏感です。一方で、正しさを求めすぎると、関係が緊張しやすくなることがあります。相手の不完全さを許す余白も、長く続く関係には必要です。', '大切な人には、正しさを指摘する前に、自分が何を大切にしたかったのかを穏やかに伝えてください。'),
  ('kengyu', 'stomach', '人生後半ほど誇れる生き方を求める', '人生が進むほど、あなたは自分が納得して誇れる生き方を大切にしたくなります。表面的な成功より、信頼されること、役割を果たすこと、美しく整っていることに満たされやすいタイプです。自分に恥じない選択が心の支えになります。', '長期的には、どんな肩書きや役割を持つかより、それをどう誠実に果たすかが重要になります。年齢を重ねるほど、いい加減な環境や雑な関係には違和感が強くなるでしょう。信頼、品位、責任がそろう場所で力が戻ります。ただし、人生を完璧に整えようとしすぎず、少し肩の力を抜くことも大切です。', '将来を考えるときは、条件だけでなく「その選択を自分が誇れるか」を基準に入れてください。'),
  ('ryuko', 'head', '未知の可能性から判断する人', 'あなたは物事を判断するとき、今ある正解だけでなく、まだ見えていない可能性に意識が向きやすい人です。新しい情報、異なる文化、別のやり方に触れることで視野が広がります。常識をそのまま受け入れるより、自分で確かめたいタイプです。', '価値観の面では、変化、自由、探究が大切な軸になります。既存のルールをただ守るより、なぜそうなっているのか、他に方法はないのかを考えます。その姿勢は発見につながりますが、安定したものを退屈と決めつけると、積み上げる力が弱くなることがあります。新しさと継続のバランスを取ることで判断が安定します。', '迷ったときは、新しい可能性だけでなく、それを続けた先に何が残るかも考えてみてください。'),
  ('ryuko', 'chest', '変化の中で成長する探究者', 'あなたの中心には、未知のものを理解しようとする探究心があります。同じ場所で同じことを繰り返すより、新しい知識や環境に触れることで自分らしさが目を覚まします。変化を経験に変えながら、独自の世界を広げていくタイプです。', '本質的には、自由に学び、動きながら理解する人です。既存の枠に収まりきらない感覚があり、経験を通して自分の答えを作っていきます。一方で、安定だけを求められる環境では力が出にくくなることがあります。変化を求める気持ちを散漫さで終わらせず、探究テーマとして育てることが大切です。', '自分らしさを出すには、変化を怖がるより、学びとして回収できる環境を選んでください。'),
  ('ryuko', 'left_hand', '仕事では新しい仕組みを探る力が活きる', '仕事では、調査、改善、企画、新規領域、異なる分野をつなぐ場面で力を発揮します。決まった手順を守るだけの仕事より、未知の課題を解きほぐす仕事に向いています。変化のある環境で学び続けるほど、評価につながりやすいでしょう。', '働き方では、新しい知識や経験を取り入れられる環境が大切です。既存のやり方に疑問を持ち、別の方法を試す力があります。ただし、変化が多すぎて目的が曖昧になると、成果が散らばりやすくなります。探究するテーマを決め、学びを形に残すことで、自由さが仕事の価値に変わります。', '仕事では、新しいことに触れるだけで終わらせず、学んだことを成果物や仕組みに残すと評価されます。'),
  ('ryuko', 'right_hand', '親しい人にも自由な距離感を求める', '恋愛や身近な関係では、近さだけでなく、自由に考えたり動いたりできる余白を大切にします。相手と深く関わりたい気持ちはあっても、束縛されると息苦しさを感じやすいでしょう。互いに世界を広げ合える関係に惹かれます。', '親しい関係では、刺激や学びがある相手に魅力を感じやすいです。一緒に新しい経験をしたり、知らない世界を見せ合ったりすることで関係が深まります。一方で、安定を求める相手には、距離があるように見えることがあります。自由が必要な理由を伝えることで、誤解を減らせます。', '大切な人には、ひとりの時間が必要なことを冷たさではなく、自分を整える時間として説明してみてください。'),
  ('ryuko', 'stomach', '人生後半ほど新しい世界が必要になる', '人生が進むほど、あなたは変化や学びのない生活に物足りなさを感じやすくなります。安定は大切ですが、心が動く新しいテーマを持つことで元気が戻ります。旅、学び、転機、異分野との出会いが、長期的な充実につながります。', '長期的には、同じ場所に留まることより、経験を通して世界を広げることがテーマになります。年齢を重ねても、新しいことを学ぶ余地があるほど心が若く保たれます。ただし、変化を求めるあまり生活の土台が揺らぐと疲れやすくなります。安定した基盤の上に、自由な探究を置く設計が合っています。', '将来の計画には、安定だけでなく、学び直しや旅、新しい挑戦の余白を入れておくと満たされやすくなります。'),
  ('gyokudo', 'head', '理解してから判断する人', 'あなたは物事を判断するとき、勢いや感情だけでなく、背景や仕組みを理解してから動きたいタイプです。なぜそうなるのかを知ることで安心し、納得感のある選択ができます。情報を整理し、学びながら答えを出していく人です。', '価値観の面では、知識、理解、筋道が大切な軸になります。表面的な流行より、根拠や背景に関心が向きやすいでしょう。学んだことを体系化する力がありますが、理解が足りないと感じると動き出せないこともあります。完璧にわかってからではなく、学びながら進める姿勢を持つと可能性が広がります。', '迷ったときは、必要な情報を集めつつ、まず小さく試す期限を決めると動きやすくなります。'),
  ('gyokudo', 'chest', '学びを深めて信頼を得る人', 'あなたの中心には、物事を深く理解し、知識を積み重ねる力があります。すぐに結論を出すより、背景や意味を丁寧に読み解くタイプです。学んだことを自分の中で整理し、人にわかりやすく伝えることで魅力が伝わります。', '本質的には、知性と保護の感覚を持つ人です。知らないことを学び、理解し、必要な人へ届けることに向いています。伝統や専門性、教育、研究とも相性があります。一方で、考えすぎて自分の気持ちを後回しにすることがあります。知識だけでなく、自分の実感も大切にするとバランスが取れます。', '自分らしさを出すには、学んだことを自分の中だけに留めず、誰かに伝える形にしてみてください。'),
  ('gyokudo', 'left_hand', '仕事では専門性と説明力が活きる', '仕事では、学ぶ、調べる、整理する、教える、仕組みを理解する場面で力を発揮します。専門性を深めるほど信頼されやすいタイプです。教育、研究、企画、分析、コンサルティング、ドキュメント作成などと相性があります。', '働き方では、知識を深められる環境や、体系的に考える時間があるほど力が出ます。複雑な内容を整理し、人に伝わる形にすることが得意です。ただし、情報収集に時間をかけすぎると、実行が遅れることがあります。学びを成果に変える締切やアウトプットの場を持つと評価されやすくなります。', '仕事では、学んだことを資料・提案・教育・仕組みとして残すと、専門性が評価に変わります。'),
  ('gyokudo', 'right_hand', '親しい人には理解で寄り添う', '恋愛や身近な関係では、感情的に盛り上がるだけでなく、相手を理解したい気持ちが強く出ます。相手の背景や考え方を知ることで安心します。ただし、気持ちを分析しすぎると、相手には少し距離があるように見えることがあります。', '親しい関係では、話を聞き、相手を理解しようとする姿勢が魅力になります。落ち着いた言葉で支えることができる人です。一方で、感情を整理してから話そうとするため、本音が出るまで時間がかかることがあります。正しい説明だけでなく、今感じていることをそのまま伝えると関係が深まります。', '大切な人には、理由を説明する前に「私はこう感じた」と短く伝える練習をしてみてください。'),
  ('gyokudo', 'stomach', '人生後半ほど学びが支えになる', '人生が進むほど、あなたは学び続けることや、知識を深めることに満たされやすくなります。表面的な忙しさより、意味を理解できる時間が大切になります。自分の専門性や知恵を誰かに渡せるようになると、長期的な充実感が増します。', '長期的には、知識や経験をどう蓄積し、誰に伝えるかがテーマになります。年齢を重ねるほど、ただ働くだけでなく、自分が学んできたことを整理し、残し、教えることに価値を感じやすいでしょう。学びの場を持ち続けることが、心の安定にもつながります。考える時間と実践する時間の両方を持つことが大切です。', '将来の生活には、学び直しや専門性の深化、人に教える機会を入れておくと充実しやすくなります。')
) as v(star_code, position_code, title, free_text, premium_text, advice_text)
join public.sanmei_stars st on st.code = v.star_code
join public.sanmei_positions ps on ps.code = v.position_code;

commit;
